                  {
                            "tier": "junior",
                            "code": "// === JUNIOR EXAMPLE ===\n// TASK      - Real-world usage of Proxy — Intercept Object Operations — common patterns you'll see in production.\n// APPROACH  - Combine Proxy — Intercept Object Operations with related functions; handle common edge cases.\n// STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n// WEAKNESSES- May need optimization for large datasets or complex queries.\n// APPROACH  - validation, reactive state, and convenience proxies.\n// STRENGTHS - covers the 80% case: set validation, reactive proxy pattern.\n// WEAKNESSES- no Reflect, no has trap, no revocable proxy.\n//\n// GOAL: validation, reactive state, and convenience proxies\n// WHY: validation trap\nconst validator = {\n  set(target, prop, value) {\n    if (prop === 'age' && (!Number.isInteger(value) || value < 0 || value > 150)) {\n      throw new RangeError('Age must be 0-150');\n    }\n    target[prop] = value;\n    return true;\n  }\n};\nconst person = new Proxy({}, validator);\n// WHY: reactive proxy\nfunction reactive(obj, onChange) {\n  return new Proxy(obj, {\n    set(t, p, v) {\n      const old = t[p];\n      t[p] = v;\n      if (old !== v) onChange(p, v, old);\n      return true;\n    }\n  });\n}"
                  },
                  {
                            "tier": "senior",
                            "code": "// === SENIOR EXAMPLE ===\n// TASK      - Advanced usage of Proxy — Intercept Object Operations — performance, edge cases, and expert patterns.\n// APPROACH  - Production-grade patterns; optimization; handling complex scenarios.\n// STRENGTHS - Complete; handles edge cases, performance, and maintainability.\n// WEAKNESSES- Complex; requires deep knowledge to understand and maintain.\n// APPROACH  - production Proxy patterns: reactive store with Reflect,\n//             auto-vivification, and revocable access control.\n// STRENGTHS - reactive store with Reflect; auto-vivification;\n//             revocable capability proxy.\n// WEAKNESSES- no performance benchmark; no Proxy invariants discussion.\n//\n// GOAL: use Proxy for meta-programming safely\n// WHY: use Reflect inside traps to preserve default behavior\n// Reactive store with Reflect and deep change notification\nclass ReactiveStore {\n  #target; #listeners = new Set();\n  constructor(target) { this.#target = target; }\n  get proxy() {\n    return new Proxy(this.#target, {\n      get: (t, k, r) => Reflect.get(t, k, r),\n      set: (t, k, v, r) => {\n        const old = t[k];\n        const ok = Reflect.set(t, k, v, r);\n        if (ok && old !== v) this.#listeners.forEach(fn => fn(k, v, old));\n        return ok;\n      },\n      has: (t, k) => Reflect.has(t, k),\n      deleteProperty: (t, k) => {\n        const ok = Reflect.deleteProperty(t, k);\n        if (ok) this.#listeners.forEach(fn => fn(k, undefined, t[k]));\n        return ok;\n      },\n    });\n  }\n  subscribe(fn) { this.#listeners.add(fn); return () => this.#listeners.delete(fn); }\n}\n// Auto-vivification: create nested objects on access\nfunction autoVivify() {\n  return new Proxy({}, {\n    get(target, key) {\n      if (!(key in target)) target[key] = autoVivify();\n      return target[key];\n    },\n  });\n}\nconst tree = autoVivify();\ntree.a.b.c = 42; // creates intermediate objects automatically\n// Revocable capability proxy\nfunction createCapability(target, allowedKeys) {\n  const { proxy, revoke } = Proxy.revocable(target, {\n    get(t, k) {\n      if (!allowedKeys.includes(k)) throw new Error(`Access denied: ${k}`);\n      return Reflect.get(t, k);\n    },\n    set(t, k, v) {\n      if (!allowedKeys.includes(k)) throw new Error(`Access denied: ${k}`);\n      return Reflect.set(t, k, v);\n    },\n  });\n  return { proxy, revoke };\n}\n// Decision rule:\n//   validation / logging                                    -> Proxy wrapper\n//   reactive state                                          -> Proxy + Reflect\n//   auto-vivification                                       -> recursive get trap\n//   access control / revocation                             -> Proxy.revocable\n//\n// Anti-pattern: implementing only get and ignoring has/ownKeys;\n//   using Proxy on hot paths without profiling."
                  }
