                            "tier": "junior",
                            "code": "// === JUNIOR EXAMPLE ===\n// TASK      - Real-world usage of Reflect API — Safe Meta-Operations — common patterns you'll see in production.\n// APPROACH  - Combine Reflect API — Safe Meta-Operations with related functions; handle common edge cases.\n// STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n// WEAKNESSES- May need optimization for large datasets or complex queries.\n// APPROACH  - Reflect inside Proxy traps and dynamic function/constructor calls.\n// STRENGTHS - covers the 80% case: receiver-aware traps, apply, construct.\n// WEAKNESSES- no boolean return comparison, no defineProperty, no ownKeys.\n//\n// GOAL: use Reflect inside Proxy traps and dynamic calls\n// WHY: forwarding to target while preserving receiver\nconst handler = {\n  get(target, prop, receiver) {\n    console.log('GET', prop);\n    return Reflect.get(target, prop, receiver);\n  },\n  set(target, prop, value, receiver) {\n    console.log('SET', prop, value);\n    return Reflect.set(target, prop, value, receiver);\n  }\n};\nconst proxy = new Proxy({ count: 0 }, handler);\n// WHY: Reflect.apply and Reflect.construct\nfunction greet(greeting) { return `${greeting}, ${this.name}!`; }\nReflect.apply(greet, { name: 'Alice' }, ['Hello']);\nclass User { constructor(name) { this.name = name; } }\nReflect.construct(User, ['Alice']);"
