                  {
                            "tier": "senior",
                            "code": "// === SENIOR EXAMPLE ===\n// TASK      - Advanced usage of Reflect API — Safe Meta-Operations — performance, edge cases, and expert patterns.\n// APPROACH  - Production-grade patterns; optimization; handling complex scenarios.\n// STRENGTHS - Complete; handles edge cases, performance, and maintainability.\n// WEAKNESSES- Complex; requires deep knowledge to understand and maintain.\n// APPROACH  - production Reflect: receiver-aware proxy forwarding,\n//             Reflect.construct for subclassing, boolean returns for\n//             safe property manipulation, and ownKeys for complete\n//             enumeration including symbols.\n// STRENGTHS - receiver in get/set; Reflect.construct with NewTarget;\n//             boolean returns for safe define/delete; ownKeys.\n// WEAKNESSES- no performance comparison with direct property access.\n//\n// GOAL: prefer Reflect in meta-programming\n// WHY: Reflect returns booleans rather than throwing\n// Receiver-aware proxy: getters on prototype work correctly\nclass Base {\n  get derived() { return this._val * 2; }\n}\nconst proxy = new Proxy(new Base(), {\n  get(target, key, receiver) {\n    return Reflect.get(target, key, receiver);\n  },\n  set(target, key, value, receiver) {\n    return Reflect.set(target, key, value, receiver);\n  },\n});\nproxy._val = 21;\nproxy.derived; // 42 — getter runs with receiver as this\n// Reflect.construct: control prototype chain\nfunction Animal(name) { this.name = name; }\nfunction Dog(name) { return Reflect.construct(Animal, [name], Dog); }\nDog.prototype = Object.create(Animal.prototype);\nDog.prototype.bark = function() { return 'woof'; };\nconst d = new Dog('Rex');\n// d instanceof Dog && d instanceof Animal && d.bark() === 'woof'\n// Safe property manipulation with boolean returns\nfunction safeDefine(obj, key, descriptor) {\n  if (!Reflect.defineProperty(obj, key, descriptor)) {\n    throw new Error(`Cannot define ${String(key)}`);\n  }\n  return obj;\n}\nfunction safeDelete(obj, key) {\n  return Reflect.deleteProperty(obj, key);\n}\n// safeDelete({ x: 1 }, 'x') -> true\n// safeDelete(Object.freeze({ x: 1 }), 'x') -> false\n// Complete key enumeration including symbols\nconst sym = Symbol('hidden');\nconst obj = { a: 1, [sym]: 2, b: 3 };\nReflect.ownKeys(obj); // ['a', 'b', Symbol(hidden)]\n// Decision rule:\n//   Proxy trap forwarding                                     -> Reflect.*\n//   own keys incl symbols                                     -> Reflect.ownKeys\n//   dynamic function invocation                               -> Reflect.apply\n//   dynamic construction                                      -> Reflect.construct\n//   safe delete/define without throwing                       -> Reflect.deleteProperty / defineProperty\n//\n// Anti-pattern: target[prop] directly in a get trap (breaks getters\n//   in prototype chain); using Object methods in Proxy traps."
                  }
