                            "tier": "senior",
                            "code": "// === SENIOR EXAMPLE ===\n// TASK      - Advanced usage of Async Generators & Async Iteration — performance, edge cases, and expert patterns.\n// APPROACH  - Production-grade patterns; optimization; handling complex scenarios.\n// STRENGTHS - Complete; handles edge cases, performance, and maintainability.\n// WEAKNESSES- Complex; requires deep knowledge to understand and maintain.\n// APPROACH  - production async iteration: paginated API with cursor,\n//             async pipeline with filter/map/take, AbortController\n//             cancellation, and readable stream interop.\n// STRENGTHS - cursor-based pagination; composable async pipeline;\n//             AbortController cancellation; ReadableStream conversion.\n// WEAKNESSES- no backpressure handling; no error recovery strategy.\n//\n// GOAL: use async iteration effectively\n// WHY: for await...of works with any async iterable\n// Cursor-based pagination with async generator\nasync function* fetchAll(baseUrl, options = {}) {\n  let cursor = null;\n  while (true) {\n    const url = new URL(baseUrl);\n    if (cursor) url.searchParams.set('cursor', cursor);\n    const res = await fetch(url, options);\n    if (!res.ok) throw new Error(`HTTP ${res.status}`);\n    const { data, nextCursor } = await res.json();\n    if (!data.length) break;\n    yield* data;\n    if (!nextCursor) break;\n    cursor = nextCursor;\n  }\n}\n// Composable async pipeline helpers\nasync function* asyncMap(iter, fn) {\n  for await (const x of iter) yield await fn(x);\n}\nasync function* asyncFilter(iter, pred) {\n  for await (const x of iter) if (await pred(x)) yield x;\n}\nasync function* asyncTake(iter, n) {\n  let i = 0;\n  for await (const x of iter) { if (i++ >= n) return; yield x; }\n}\n// Usage: lazy async pipeline\nconst pipeline = asyncTake(\n  asyncFilter(fetchAll('/api/users'), u => u.active),\n  10\n);\nfor await (const user of pipeline) console.log(user.name);\n// Cancellable async iteration with AbortController\nasync function* cancellableFetch(url, signal) {\n  for (let page = 1; ; page++) {\n    if (signal.aborted) return;\n    const res = await fetch(`${url}?page=${page}`, { signal });\n    const data = await res.json();\n    if (!data.length) return;\n    yield* data;\n  }\n}\nconst controller = new AbortController();\nsetTimeout(() => controller.abort(), 5000);\nfor await (const item of cancellableFetch('/api/items', controller.signal)) {\n  console.log(item);\n}\n// Convert async iterable to ReadableStream (Web Streams API)\nfunction toReadableStream(asyncIterable) {\n  const reader = asyncIterable[Symbol.asyncIterator]();\n  return new ReadableStream({\n    async pull(controller) {\n      const { value, done } = await reader.next();\n      if (done) controller.close();\n      else controller.enqueue(value);\n    },\n    cancel() { reader.return?.(); },\n  });\n}\n// Decision rule:\n//   paginated/streaming data                                  -> async generator\n//   event streams                                             -> Symbol.asyncIterator\n//   transform async stream                                    -> async generator pipeline\n//   cancellable async iteration                               -> AbortController + signal\n//   Web Streams interop                                       -> toReadableStream helper\n//   one-shot async values                                     -> Promise / async/await\n//\n// Anti-pattern: buffering all async results into an array; using\n//   regular for...of on async iterables (won't work)."
