                            "tier": "senior",
                            "code": "// === SENIOR EXAMPLE ===\n// TASK      - Advanced usage of Proxy Traps Deep Dive — performance, edge cases, and expert patterns.\n// APPROACH  - Production-grade patterns; optimization; handling complex scenarios.\n// STRENGTHS - Complete; handles edge cases, performance, and maintainability.\n// WEAKNESSES- Complex; requires deep knowledge to understand and maintain.\n// APPROACH  - production Proxy trap patterns: virtual object with all\n//             traps, getOwnPropertyDescriptor for property hiding,\n//             and Proxy invariants compliance.\n// STRENGTHS - virtual object pattern; property hiding via ownKeys +\n//             getOwnPropertyDescriptor; invariant compliance.\n// WEAKNESSES- no performance benchmark; no getPrototypeOf/setPrototypeOf.\n//\n// GOAL: use Proxy traps responsibly\n// WHY: implement only the traps your use case needs\n// Virtual object: no real target, all properties computed\nfunction createVirtualObject(schema) {\n  const data = {};\n  return new Proxy({}, {\n    get(t, key, receiver) {\n      if (key in schema) return schema[key].get?.(data) ?? schema[key].default;\n      return Reflect.get(t, key, receiver);\n    },\n    set(t, key, value, receiver) {\n      if (key in schema) {\n        const validator = schema[key].validate;\n        if (validator && !validator(value)) throw new TypeError(`Invalid ${key}`);\n        schema[key].set?.(data, value);\n        return true;\n      }\n      return Reflect.set(t, key, value, receiver);\n    },\n    has(t, key) { return key in schema || Reflect.has(t, key); },\n    ownKeys() { return Object.keys(schema); },\n    getOwnPropertyDescriptor(t, key) {\n      if (key in schema) {\n        return { configurable: true, enumerable: true, get: () => this.get(t, key), set: (v) => this.set(t, key, v) };\n      }\n      return Reflect.getOwnPropertyDescriptor(t, key);\n    },\n  });\n}\n// Property hiding: hide private keys from all enumeration\nfunction createProtected(target, prefix = '_') {\n  return new Proxy(target, {\n    ownKeys(t) {\n      return Reflect.ownKeys(t).filter(k => !String(k).startsWith(prefix));\n    },\n    getOwnPropertyDescriptor(t, key) {\n      if (String(key).startsWith(prefix)) return undefined;\n      return Reflect.getOwnPropertyDescriptor(t, key);\n    },\n    get(t, key, receiver) {\n      if (String(key).startsWith(prefix)) throw new Error('Private access');\n      return Reflect.get(t, key, receiver);\n    },\n  });\n}\nconst protected_ = createProtected({ _id: 1, name: 'Alice', _secret: 'x' });\nObject.keys(protected_); // ['name']\nprotected_._id; // Error: Private access\n// Decision rule:\n//   property read/write                                       -> get / set\n//   property enumeration/membership                           -> ownKeys / has\n//   function call/constructor                                 -> apply / construct\n//   prototype/descriptor control                              -> getPrototypeOf / getOwnPropertyDescriptor\n//   virtual/computed properties                               -> all traps with no real target\n//   property hiding                                           -> ownKeys + getOwnPropertyDescriptor\n//\n// Anti-pattern: implementing all 13 traps \"just in case\"; violating\n//   Proxy invariants (e.g., returning false from set on non-configurable\n//   property)."
