        id: "tagged-templates",
        fn: "Tagged Template Literals",
        desc: "Process template literals with custom functions to build DSLs, HTML, SQL, and complex string interpolations.",
        category: "DSL & Metaprogramming",
        subtitle: "Tagged templates, string processing, SQL builders, HTML templates",
        signature: "tag`string ${expr} string`  →  tag(strings, ...values)",
        descLong: "A tagged template is a function called with a template literal. The function receives an array of static strings and the interpolated values separately. Build DSLs (html`<div>${x}</div>`), SQL builders with escaping, or custom string formatting. Tags are zero-runtime cost — no parsing overhead. The tag function controls how the strings and values are combined.",
        examples: [
                  {
                            "tier": "intro",
                            "code": "// === ENTRY-LEVEL EXAMPLE ===\n// TASK      - Basic usage of Tagged Template Literals — understand the core syntax and behavior.\n// APPROACH  - Simple example with minimal parameters; no edge cases.\n// STRENGTHS - Clear, readable; shows the fundamental pattern.\n// WEAKNESSES- Not production-ready; no error handling or complex scenarios.\n// APPROACH  - the simplest tagged template: process strings and values.\n// STRENGTHS - shows tag function signature, strings array, values spread.\n// WEAKNESSES- no escaping, no DSL, no raw strings.\n//\n// GOAL: process a template literal with a tag function\nfunction tag(strings, ...values) {\n  return strings.reduce((acc, s, i) => acc + s + (values[i] ?? ''), '');\n}\nconst name = 'Alice';\ntag`Hello, ${name}!`; // 'Hello, Alice!'"
                  },
                  {
                            "tier": "junior",
                            "code": "// === JUNIOR EXAMPLE ===\n// TASK      - Real-world usage of Tagged Template Literals — common patterns you'll see in production.\n// APPROACH  - Combine Tagged Template Literals with related functions; handle common edge cases.\n// STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n// WEAKNESSES- May need optimization for large datasets or complex queries.\n// APPROACH  - safe DSLs: HTML escaping and SQL parameterization.\n// STRENGTHS - covers the 80% case: HTML escape tag, SQL parameterized tag.\n// WEAKNESSES- no raw strings, no nested templates, no caching.\n//\n// GOAL: safe DSLs with tagged templates\n// WHY: HTML escaping\nfunction html(strings, ...values) {\n  const escape = s => String(s)\n    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')\n    .replace(/\"/g, '&quot;').replace(/'/g, '&#x27;');\n  return strings.reduce((acc, s, i) => acc + s + escape(values[i] ?? ''), '');\n}\n// WHY: SQL parameterization\nfunction sql(strings, ...values) {\n  const params = [];\n  const query = strings.reduce((acc, s, i) => {\n    if (i >= values.length) return acc + s;\n    params.push(values[i]);\n    return acc + s + `${params.length}`;\n  }, '');\n  return { query, params };\n}"
                  },
                  {
                            "tier": "senior",
                            "code": "// === SENIOR EXAMPLE ===\n// TASK      - Advanced usage of Tagged Template Literals — performance, edge cases, and expert patterns.\n// APPROACH  - Production-grade patterns; optimization; handling complex scenarios.\n// STRENGTHS - Complete; handles edge cases, performance, and maintainability.\n// WEAKNESSES- Complex; requires deep knowledge to understand and maintain.\n// APPROACH  - production tagged template DSLs: safe HTML with nested\n//             templates, SQL builder with conditionals, and string.raw\n//             for literal backslashes.\n// STRENGTHS - nested template support in HTML; SQL conditional builder;\n//             String.raw for regex/paths; cached strings array.\n// WEAKNESSES- no i18n integration; no performance benchmark.\n//\n// GOAL: build DSLs safely with tagged templates\n// WHY: strings and values are passed separately; zero runtime parsing cost\n// Safe HTML with nested template support\nfunction html(strings, ...values) {\n  const escape = s => {\n    if (s == null) return '';\n    if (typeof s === 'object' && s.__safe_html) return s.value;\n    return String(s)\n      .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')\n      .replace(/\"/g, '&quot;').replace(/'/g, '&#x27;');\n  };\n  let result = '';\n  for (let i = 0; i < strings.length; i++) {\n    result += strings[i];\n    if (i < values.length) result += escape(values[i]);\n  }\n  return result;\n}\n// Mark safe HTML to skip escaping\nconst safe = (value) => ({ __safe_html: true, value });\nconst user = '<script>alert(1)</script>';\nconst greeting = html`<div>${safe('<b>Welcome</b>')} ${user}</div>`;\n// '<div><b>Welcome</b> &lt;script&gt;alert(1)&lt;/script&gt;</div>'\n// SQL builder with conditionals\nfunction sql(strings, ...values) {\n  const params = [];\n  let query = '';\n  for (let i = 0; i < strings.length; i++) {\n    query += strings[i];\n    if (i < values.length) {\n      const v = values[i];\n      if (v && v.__raw_sql) {\n        query += v.value; // inline raw SQL fragment\n      } else {\n        params.push(v);\n        query += `${params.length}`;\n      }\n    }\n  }\n  return { query: query.trim(), params };\n}\nconst raw = (value) => ({ __raw_sql: true, value });\nconst status = 'active';\nconst limit = 10;\nconst { query, params } = sql`SELECT * FROM users WHERE status = ${status} ${raw('ORDER BY created_at DESC')} LIMIT ${limit}`;\n// query: 'SELECT * FROM users WHERE status = $1 ORDER BY created_at DESC LIMIT $2'\n// params: ['active', 10]\n// String.raw: preserve backslashes (regex, Windows paths)\nconst regex = new RegExp(String.raw`\\d${'+'}\\d`); // /d+d/\nconst path = String.raw`C:\\Users\\\\Documents`; // 'C:\\UsersDocuments'\n// Decision rule:\n//   safe HTML rendering                                       -> escaping tag\n//   SQL query building                                        -> parameterized tag\n//   CSS-in-JS / GraphQL DSLs                                  -> tagged template\n//   regex / Windows paths with backslashes                    -> String.raw\n//   simple concatenation                                      -> plain template literal\n//\n// Anti-pattern: interpolating raw user input into SQL/HTML without\n//   escaping or parameterization."
                  }
        ],
